const campaignData = {
  adSpend: 1500000,
  clicks: 75000,
  installs: 12000,
  firstOpens: 10800,
  registrations: 3240
};

function calcCPI(adSpend, installs) {
  return adSpend / installs;
}

function calcInstallRate(clicks, installs) {
  return (installs / clicks) * 100;
}

function calcFirstOpenRate(installs, firstOpens) {
  return (firstOpens / installs) * 100;
}

function calcRegistrationRate(firstOpens, registrations) {
  return (registrations / firstOpens) * 100;
}

console.log('CPI:', '¥' + calcCPI(campaignData.adSpend, campaignData.installs).toFixed(0));
console.log('クリック→インストール率:', calcInstallRate(campaignData.clicks, campaignData.installs).toFixed(1) + '%');
console.log('インストール→first_open率:', calcFirstOpenRate(campaignData.installs, campaignData.firstOpens).toFixed(1) + '%');
console.log('first_open→登録率:', calcRegistrationRate(campaignData.firstOpens, campaignData.registrations).toFixed(1) + '%');
